"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[70700],{36750(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>o,default:()=>h,frontMatter:()=>r,metadata:()=>i,toc:()=>d});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets and IAS 2 Inventories/holdings-of-cryptocurrencies-d65a896f52","title":"Holdings of Cryptocurrencies","description":"June 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets and IAS 2 Inventories/Holdings of Cryptocurrencies.md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets and IAS 2 Inventories","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/holdings-of-cryptocurrencies-d65a896f52","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/holdings-of-cryptocurrencies-d65a896f52","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"holdings-of-cryptocurrencies-d65a896f52","title":"Holdings of Cryptocurrencies","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/holdings-of-cryptocurrencies-d65a896f52","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/configuration-or-customisation-costs-acd1e0b2c4"},"next":{"title":"Subsequent Expenditure on Biological Assets (IAS 41)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-41-agriculture-c896891f3d/subsequent-expenditure-on-biological-9da09e016f"}}');var a=n(74848),s=n(28453);let r={id:"holdings-of-cryptocurrencies-d65a896f52",title:"Holdings of Cryptocurrencies",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/holdings-of-cryptocurrencies-d65a896f52",sidebar_position:2},o="Holdings of Cryptocurrencies",c={},d=[{value:"Nature of a cryptocurrency",id:"nature-of-a-cryptocurrency",level:2},{value:"Which IFRS Standard applies to holdings of cryptocurrencies?",id:"which-ifrs-standard-applies-to-holdings-of-cryptocurrencies",level:2},{value:"Intangible Asset",id:"intangible-asset",level:2},{value:"Financial asset",id:"financial-asset",level:2},{value:"Cash",id:"cash",level:2},{value:"Inventory",id:"inventory",level:2},{value:"Disclosure",id:"disclosure",level:2}];function l(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"holdings-of-cryptocurrencies",children:"Holdings of Cryptocurrencies"})}),"\n",(0,a.jsx)(t.p,{children:"June 2019"}),"\n",(0,a.jsx)(t.p,{children:"The Committee discussed how IFRS Standards apply to holdings of cryptocurrencies."}),"\n",(0,a.jsx)(t.p,{children:"The Committee noted that a range of cryptoassets exist. For the purposes of its discussion, the Committee considered a subset of cryptoassets with all the following characteristics that this agenda decision refers to as a \u2018cryptocurrency\u2019:"}),"\n",(0,a.jsx)(t.p,{children:"a. a digital or virtual currency recorded on a distributed ledger that uses cryptography for security.\nb. not issued by a jurisdictional authority or other party.\nc. does not give rise to a contract between the holder and another party."}),"\n",(0,a.jsx)(t.h2,{id:"nature-of-a-cryptocurrency",children:"Nature of a cryptocurrency"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 8 of IAS 38 Intangible Assets defines an intangible asset as \u2018an identifiable non-monetary asset without physical substance\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 12 of IAS 38 states that an asset is identifiable if it is separable or arises from contractual or other legal rights. An asset is separable if it \u2018is capable of being separated or divided from the entity and sold, transferred, licensed, rented or exchanged, either individually or together with a related contract, identifiable asset or liability\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 16 of IAS 21 The Effects of Changes in Foreign Exchange Rates states that \u2018the essential feature of a non-monetary item is the absence of a right to receive (or an obligation to deliver) a fixed or determinable number of units of currency\u2019."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that a holding of cryptocurrency meets the definition of an intangible asset in IAS 38 on the grounds that (a) it is capable of being separated from the holder and sold or transferred individually; and (b) it does not give the holder a right to receive a fixed or determinable number of units of currency."}),"\n",(0,a.jsx)(t.h2,{id:"which-ifrs-standard-applies-to-holdings-of-cryptocurrencies",children:"Which IFRS Standard applies to holdings of cryptocurrencies?"}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that IAS 2 Inventories applies to cryptocurrencies when they are held for sale in the ordinary course of business. If IAS 2 is not applicable, an entity applies IAS 38 to holdings of cryptocurrencies. The Committee considered the following in reaching its conclusion."}),"\n",(0,a.jsx)(t.h2,{id:"intangible-asset",children:"Intangible Asset"}),"\n",(0,a.jsx)(t.p,{children:"IAS 38 applies in accounting for all intangible assets except:"}),"\n",(0,a.jsx)(t.p,{children:"a. those that are within the scope of another Standard;\nb. financial assets, as defined in IAS 32 Financial Instruments: Presentation;\nc. the recognition and measurement of exploration and evaluation assets; and\nd. expenditure on the development and extraction of minerals, oil, natural gas and similar non-regenerative resources."}),"\n",(0,a.jsx)(t.p,{children:"Accordingly, the Committee considered whether a holding of cryptocurrency meets the definition of a financial asset in IAS 32 or is within the scope of another Standard."}),"\n",(0,a.jsx)(t.h2,{id:"financial-asset",children:"Financial asset"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 11 of IAS 32 defines a financial asset. In summary, a financial asset is any asset that is: (a) cash; (b) an equity instrument of another entity; (c) a contractual right to receive cash or another financial asset from another entity; (d) a contractual right to exchange financial assets or financial liabilities with another entity under particular conditions; or (e) a particular contract that will or may be settled in the entity\u2019s own equity instruments."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that a holding of cryptocurrency is not a financial asset. This is because a cryptocurrency is not cash (see below). Nor is it an equity instrument of another entity. It does not give rise to a contractual right for the holder and it is not a contract that will or may be settled in the holder\u2019s own equity instruments."}),"\n",(0,a.jsx)(t.h2,{id:"cash",children:"Cash"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph AG3 of IAS 32 states that \u2018currency (cash) is a financial asset because it represents the medium of exchange and is therefore the basis on which all transactions are measured and recognised in financial statements. A deposit of cash with a bank or similar financial institution is a financial asset because it represents the contractual right of the depositor to obtain cash from the institution or to draw a cheque or similar instrument against the balance in favour of a creditor in payment of a financial liability\u2019."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that the description of cash in paragraph AG3 of IAS 32 implies that cash is expected to be used as a medium of exchange (ie used in exchange for goods or services) and as the monetary unit in pricing goods or services to such an extent that it would be the basis on which all transactions are measured and recognised in financial statements."}),"\n",(0,a.jsx)(t.p,{children:"Some cryptocurrencies can be used in exchange for particular good or services. However, the Committee noted that it is not aware of any cryptocurrency that is used as a medium of exchange and as the monetary unit in pricing goods or services to such an extent that it would be the basis on which all transactions are measured and recognised in financial statements. Consequently, the Committee concluded that a holding of cryptocurrency is not cash because cryptocurrencies do not currently have the characteristics of cash."}),"\n",(0,a.jsx)(t.h2,{id:"inventory",children:"Inventory"}),"\n",(0,a.jsx)(t.p,{children:"IAS 2 applies to inventories of intangible assets. Paragraph 6 of that Standard defines inventories as assets:"}),"\n",(0,a.jsx)(t.p,{children:"a. held for sale in the ordinary course of business;\nb. in the process of production for such sale; or\nc. in the form of materials or supplies to be consumed in the production process or in the rendering of services."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that an entity may hold cryptocurrencies for sale in the ordinary course of business. In that circumstance, a holding of cryptocurrency is inventory for the entity and, accordingly, IAS 2 applies to that holding."}),"\n",(0,a.jsx)(t.p,{children:"The Committee also observed that an entity may act as a broker-trader of cryptocurrencies. In that circumstance, the entity considers the requirements in paragraph 3(b) of IAS 2 for commodity broker-traders who measure their inventories at fair value less costs to sell. Paragraph 5 of IAS 2 states that broker-traders are those who buy or sell commodities for others or on their own account. The inventories referred to in paragraph 3(b) are principally acquired with the purpose of selling in the near future and generating a profit from fluctuations in price or broker-traders\u2019 margin."}),"\n",(0,a.jsx)(t.h2,{id:"disclosure",children:"Disclosure"}),"\n",(0,a.jsx)(t.p,{children:"In addition to disclosures otherwise required by IFRS Standards, an entity is required to disclose any additional information that is relevant to an understanding of its financial statements (paragraph 112 of IAS 1 Presentation of Financial Statements). In particular, the Committee noted the following disclosure requirements in the context of holdings of cryptocurrencies:"}),"\n",(0,a.jsx)(t.p,{children:"a. An entity provides the disclosures required by (i) paragraphs 36\u201339 of IAS 2 for cryptocurrencies held for sale in the ordinary course of business; and (ii)paragraphs 118\u2013128 of IAS 38 for holdings of cryptocurrencies to which it applies IAS 38.\nb. If an entity measures holdings of cryptocurrencies at fair value, paragraphs 91\u201399 of IFRS 13 Fair Value Measurement specify applicable disclosure requirements.\nc. Applying paragraph 122 of IAS 1, an entity discloses judgements that its management has made regarding its accounting for holdings of cryptocurrencies if those are part of the judgements that had the most significant effect on the amounts recognised in the financial statements.\nd. Paragraph 21 of IAS 10 Events after the Reporting Period requires an entity to disclose details of any material non-adjusting events, including information about the nature of the event and an estimate of its financial effect (or a statement that such an estimate cannot be made). For example, an entity holding cryptocurrencies would consider whether changes in the fair value of those holdings after the reporting period are of such significance that non-disclosure could influence the economic decisions that users of financial statements make on the basis of the financial statements."})]})}function h(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},28453(e,t,n){n.d(t,{R:()=>r,x:()=>o});var i=n(96540);let a={},s=i.createContext(a);function r(e){let t=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),i.createElement(s.Provider,{value:t},e.children)}}}]);